// Customer order details
const customerName: string = 'alice johnson';
const product: string = 'Wireless Keyboard';
const orderId: string = 'ORD-3847';
// Capitalize the customer name properly
const formattedName: string =
  customerName.charAt(0).toUpperCase() + customerName.slice(1);
// But that only capitalizes 'A', not 'J' — a real function would split by space
// Use a template literal to build the email body
const emailBody: string = `Hi ${formattedName}, thank you for your order of ${product}. Your order number is ${orderId}.`;
console.log(emailBody);
// Check if the order ID contains 'ORD'
const isStandardOrder: boolean = orderId.includes('ORD');
console.log('Standard order:', isStandardOrder);
// Expected:
// Hi Alice johnson, thank you for your order of Wireless Keyboard. Your order number is ORD-3847.
// Standard order: true
